  @protected
  void sse_encode_edit_op(EditOp self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case EditOp_Filter(filter: final filter):
        sse_encode_i_32(0, serializer);
        sse_encode_box_autoadd_image_filter(filter, serializer);
      case EditOp_Resize(
        width: final width,
        height: final height,
        algorithm: final algorithm,
      ):
        sse_encode_i_32(1, serializer);
        sse_encode_u_32(width, serializer);
        sse_encode_u_32(height, serializer);
        sse_encode_resize_algorithm(algorithm, serializer);
      case EditOp_Crop(
        x: final x,
        y: final y,
        width: final width,
        height: final height,
      ):
        sse_encode_i_32(2, serializer);
        sse_encode_u_32(x, serializer);
        sse_encode_u_32(y, serializer);
        sse_encode_u_32(width, serializer);
        sse_encode_u_32(height, serializer);
      case EditOp_Rotate(rotation: final rotation):
        sse_encode_i_32(3, serializer);
        sse_encode_rotation(rotation, serializer);
    }
  }

