  @protected
  void sse_encode_image_filter(ImageFilter self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case ImageFilter_Blur(radius: final radius):
        sse_encode_i_32(0, serializer);
        sse_encode_u_32(radius, serializer);
      case ImageFilter_Sharpen():
        sse_encode_i_32(1, serializer);
      case ImageFilter_Brightness(amount: final amount):
        sse_encode_i_32(2, serializer);
        sse_encode_i_16(amount, serializer);
      case ImageFilter_Contrast(amount: final amount):
        sse_encode_i_32(3, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Saturation(amount: final amount):
        sse_encode_i_32(4, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_HueRotate(degrees: final degrees):
        sse_encode_i_32(5, serializer);
        sse_encode_f_32(degrees, serializer);
      case ImageFilter_Oil(radius: final radius, intensity: final intensity):
        sse_encode_i_32(6, serializer);
        sse_encode_u_32(radius, serializer);
        sse_encode_f_64(intensity, serializer);
      case ImageFilter_FrostedGlass():
        sse_encode_i_32(7, serializer);
      case ImageFilter_Pixelize(size: final size):
        sse_encode_i_32(8, serializer);
        sse_encode_u_32(size, serializer);
      case ImageFilter_Solarize():
        sse_encode_i_32(9, serializer);
      case ImageFilter_Preset(preset: final preset, strength: final strength):
        sse_encode_i_32(10, serializer);
        sse_encode_filter_preset(preset, serializer);
        sse_encode_f_32(strength, serializer);
      case ImageFilter_Warmth(amount: final amount):
        sse_encode_i_32(11, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Fade(amount: final amount):
        sse_encode_i_32(12, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Vignette(amount: final amount):
        sse_encode_i_32(13, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Highlights(amount: final amount):
        sse_encode_i_32(14, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Shadows(amount: final amount):
        sse_encode_i_32(15, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Structure(amount: final amount):
        sse_encode_i_32(16, serializer);
        sse_encode_f_32(amount, serializer);
      case ImageFilter_Mood(preset: final preset, strength: final strength):
        sse_encode_i_32(17, serializer);
        sse_encode_mood_filter_preset(preset, serializer);
        sse_encode_f_32(strength, serializer);
      case ImageFilter_SwipeLook(
        preset: final preset,
        strength: final strength,
      ):
        sse_encode_i_32(18, serializer);
        sse_encode_swipe_look_preset(preset, serializer);
        sse_encode_f_32(strength, serializer);
      case ImageFilter_LutPng(
        pngBytes: final pngBytes,
        strength: final strength,
      ):
        sse_encode_i_32(19, serializer);
        sse_encode_list_prim_u_8_strict(pngBytes, serializer);
        sse_encode_f_32(strength, serializer);
      case ImageFilter_SkinSmooth(strength: final strength):
        sse_encode_i_32(20, serializer);
        sse_encode_f_32(strength, serializer);
      case ImageFilter_Beauty(params: final params):
        sse_encode_i_32(21, serializer);
        sse_encode_box_autoadd_beauty_params(params, serializer);
    }
  }

